// NASA BRU 4.97-in radial-inflow turbine map
// From digitized NASA TN D-5090 (1969) argon cold-flow rig (Fig 8 flow, Fig 11 eff).
// NPSS turbine map: a 'Subelement TurbinePRmap S_map' block. Corrected speed and PRESSURE
// RATIO are the independents; the tables TB_Wp, TB_eff output corrected flow (WpMap) and
// efficiency (effMap).
// Flow: per-speed 3-param swallowing law Wp=W_ch*(1-PR^-a)^b (b free; tunable curvature).
// Eff: smooth polynomial fit of the collapsed eta-vs-nu curve, eta=poly(nu(NpMap,PR)).
// NpMap = N/sqrt(theta_cr) normalized to design (100% = 1.0); PRmap = inlet-total/exit-static (p1'/p3).
// effMap = total eff eta_t(1->3); WpMap = (eps*W*sqrt(theta_cr)/delta)/Wp_des, Wp_des=0.486 lb/s.
// Design: PR_ts=1.69, nu=0.7, eta_t=0.913 (PRmapDes, NpMapDes below). The
// Reynolds correction is the embedded S_Re subelement (no-op at design Re): scales effMap.
// Monatomic-gas independent (Ar/Kr/HeXe). PR is total-to-static; total-to-total variant
// in turbine_argon_tt.map (see docs/turbine.md).

Subelement TurbinePRmap S_map {
   PRmapDes = 1.690;
   NpMapDes = 1.000;
   // ReDes  = 76200.0;   // RNI = Re/ReDes; anchor = ARGON COLD-RIG design Re (TN D-5090). At the
   //   He-Xe ~10 kWe point RNI ~2 (hot mu at 1600F ~2.5x cuts Re, but the ~1.3 lb/s loop flow more
   //   than offsets) -> s_effRe ~1.01, a small FAVORABLE bump. See docs/turbine.md.

   Table TB_Wp(real NpMap, real PRmap) {
      NpMap = 0.300 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         WpMap = { 1.0186, 1.0463, 1.0696, 1.0893, 1.1061, 1.1204, 1.1327, 1.1434, 1.1526, 1.1607, 1.1677, 1.1739 }
      }
      NpMap = 0.500 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         WpMap = { 0.9982, 1.0281, 1.0535, 1.0752, 1.0938, 1.1099, 1.1238, 1.1360, 1.1466, 1.1560, 1.1642, 1.1715 }
      }
      NpMap = 0.700 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         WpMap = { 0.9453, 0.9800, 1.0099, 1.0358, 1.0583, 1.0780, 1.0953, 1.1105, 1.1240, 1.1360, 1.1467, 1.1562 }
      }
      NpMap = 0.900 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         WpMap = { 0.8756, 0.9155, 0.9502, 0.9805, 1.0070, 1.0305, 1.0512, 1.0695, 1.0859, 1.1005, 1.1136, 1.1254 }
      }
      NpMap = 1.000 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         WpMap = { 0.8276, 0.8737, 0.9134, 0.9476, 0.9772, 1.0028, 1.0251, 1.0446, 1.0616, 1.0765, 1.0897, 1.1013 }
      }
      NpMap = 1.100 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         WpMap = { 0.7181, 0.7882, 0.8464, 0.8944, 0.9340, 0.9665, 0.9932, 1.0152, 1.0334, 1.0484, 1.0608, 1.0712 }
      }
      NpMap.interp = "lagrange3";  NpMap.extrap = "linear";
      PRmap.interp = "lagrange3";  PRmap.extrap = "linear";
      extrapIsError = 0;
      printExtrap   = 0;
   }

   Table TB_eff(real NpMap, real PRmap) {
      NpMap = 0.300 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         effMap = { 0.5113, 0.4948, 0.4806, 0.4681, 0.4570, 0.4471, 0.4382, 0.4301, 0.4227, 0.4160, 0.4098, 0.4041 }
      }
      NpMap = 0.500 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         effMap = { 0.7401, 0.7215, 0.7049, 0.6901, 0.6768, 0.6647, 0.6537, 0.6437, 0.6344, 0.6259, 0.6181, 0.6107 }
      }
      NpMap = 0.700 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         effMap = { 0.8782, 0.8648, 0.8519, 0.8396, 0.8281, 0.8173, 0.8072, 0.7978, 0.7889, 0.7806, 0.7729, 0.7656 }
      }
      NpMap = 0.900 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         effMap = { 0.9133, 0.9157, 0.9146, 0.9114, 0.9070, 0.9020, 0.8965, 0.8908, 0.8852, 0.8795, 0.8740, 0.8686 }
      }
      NpMap = 1.000 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         effMap = { 0.8838, 0.8997, 0.9088, 0.9136, 0.9155, 0.9155, 0.9142, 0.9120, 0.9093, 0.9061, 0.9027, 0.8991 }
      }
      NpMap = 1.100 {
         PRmap = { 1.450, 1.500, 1.550, 1.600, 1.650, 1.700, 1.750, 1.800, 1.850, 1.900, 1.950, 2.000 }
         effMap = { 0.8704, 0.8704, 0.8738, 0.8895, 0.9000, 0.9070, 0.9115, 0.9141, 0.9154, 0.9157, 0.9153, 0.9143 }
      }
      NpMap.interp = "lagrange3";  NpMap.extrap = "linear";
      PRmap.interp = "lagrange3";  PRmap.extrap = "linear";
      extrapIsError = 0;
      printExtrap   = 0;
   }

   Subelement TurbineReynoldsEffects S_Re {
      Table s_effRe(real RNI) {
         RNI = { 0.3000, 0.3699, 0.4560, 0.5621, 0.6930, 0.8544, 1.0000, 1.0534, 1.2986, 1.6010, 1.9738, 2.4334, 3.0000 }
         s_effRe = { 0.95855, 0.96687, 0.97469, 0.98202, 0.98892, 0.99539, 1.00000, 1.00089, 1.00438, 1.00774, 1.01098, 1.01410, 1.01710 }
      }

      Table s_WpRe(real RNI) {
         RNI = { 0.3000, 0.3699, 0.4560, 0.5621, 0.6930, 0.8544, 1.0000, 1.0534, 1.2986, 1.6010, 1.9738, 2.4334, 3.0000 }
         s_WpRe = { 1.00000, 1.00000, 1.00000, 1.00000, 1.00000, 1.00000, 1.00000, 1.00000, 1.00000, 1.00000, 1.00000, 1.00000, 1.00000 }
      }
   }
}
